const VW = 925;
const VH = 726;

const SignatureLoader = ({
    duration = 3800,
    onComplete,
}) => {
    const pathRefs = useRef([]);
    const [, setProgress] = useState(0); // Use underscore to ignore the unused state value
    const [done, setDone] = useState(false);

    useEffect(() => {
        const total = PATHS.length;
        const start = performance.now();

        const tick = (now) => {
            const t = Math.min((now - start) / duration, 1);
            const show = Math.round(t * total);

            for (let i = 0; i < show; i++) {
                if (pathRefs.current[i]) {
                    pathRefs.current[i].style.opacity = "1";
                }
            }

            setProgress(Math.round(t * 100));

            if (t >= 1) {
                setTimeout(() => {
                    setDone(true);
                    onComplete?.();
                }, 600);
                return;
            }

            requestAnimationFrame(tick);
        };

        const raf = requestAnimationFrame(tick);
        return () => cancelAnimationFrame(raf);
    }, [duration, onComplete]);

    return (
        <div className={`sig-loader ${done ? "sig-loader--done" : ""}`}>
            <div className="sig-loader__wrap">
                <svg
                    className="sig-loader__svg"
                    viewBox={`0 0 ${VW} ${VH}`}
                    xmlns="http://www.w3.org/2000/svg"
                >
                    {PATHS.map((p, i) => (
                        <path
                            key={i}
                            ref={(el) => (pathRefs.current[i] = el)}
                            d={p.d}
                            fill={p.f}
                            transform={`translate(${p.x},${p.y})`}
                            style={{ opacity: 0 }}
                        />
                    ))}
                </svg>
            </div>
        </div>
    );
};

export default SignatureLoader;